ps.pstext:
if !IsFeatureImplemented(FEAT_SME) then EndOfDecode(Decode_UNDEF); end;
let esize : integer{} = 32;
let a : integer = UInt(Pn);
let b : integer = UInt(Pm);
let n : integer = UInt(Zn);
let m : integer = UInt(Zm);
let da : integer = UInt(ZAda);
let op1_unsigned : boolean = FALSE;
let op2_unsigned : boolean = FALSE;

if !IsFeatureImplemented(FEAT_SME_I16I64) then EndOfDecode(Decode_UNDEF); end;
let esize : integer{} = 64;
let a : integer = UInt(Pn);
let b : integer = UInt(Pm);
let n : integer = UInt(Zn);
let m : integer = UInt(Zm);
let da : integer = UInt(ZAda);
let op1_unsigned : boolean = FALSE;
let op2_unsigned : boolean = FALSE;

CheckStreamingSVEAndZAEnabled();
let VL : integer{} = CurrentVL();
let PL : integer{} = VL DIV 8;
let dim : integer{} = VL DIV esize;
let mask1 : bits(PL) = P{}(a);
let mask2 : bits(PL) = P{}(b);
let operand1 : bits(VL) = Z{}(n);
let operand2 : bits(VL) = Z{}(m);
let operand3 : bits(dim*dim*esize) = ZAtile{}(da, esize);
var result : bits(dim*dim*esize);
var prod : integer;

for row = 0 to dim-1 do
    for col = 0 to dim-1 do
        var sum : bits(esize) = operand3[(row*dim+col)*:esize];
        for k = 0 to 3 do
            if (ActivePredicateElement{PL}(mask1, 4*row + k, esize DIV 4) &&
                  ActivePredicateElement{PL}(mask2, 4*col + k, esize DIV 4)) then
                let op1elt : bits(esize DIV 4) = operand1[(4*row + k)*:(esize DIV 4)];
                let op2elt : bits(esize DIV 4) = operand2[(4*col + k)*:(esize DIV 4)];
                let element1 : integer = if op1_unsigned then UInt(op1elt) else SInt(op1elt);
                let element2 : integer = if op2_unsigned then UInt(op2elt) else SInt(op2elt);
                prod = element1 * element2;
                sum = sum - prod;
            end;
        end;
        result[(row*dim+col)*:esize] = sum;
    end;
end;

ZAtile{dim*dim*esize}(da, esize) = result;
